app.get('/api/records', async function(req, res) {
  try {
    var search = req.query.search;
    var status = req.query.status;
    var q = 'SELECT * FROM ' + TABLE_NAME;
    var params = [];
    var clauses = [];
    if (search) { params.push('%' + search + '%'); clauses.push('(field_1 ILIKE $' + params.length + ' OR field_2 ILIKE $' + params.length + ' OR field_3 ILIKE $' + params.length + ')'); }
    if (status && status !== 'all') { params.push(status); clauses.push('status = $' + params.length); }
    if (clauses.length) q += ' WHERE ' + clauses.join(' AND ');
    q += ' ORDER BY created_at DESC';
    var result = await pool.query(q, params);
    res.json({ success: true, records: result.rows, entity: ENTITY_LABEL });
  } catch (err) { res.status(500).json({ success: false, error: err.message }); }
});

app.get('/api/records/:id', async function(req, res) {
  try {
    var record = await pool.query('SELECT * FROM ' + TABLE_NAME + ' WHERE id = $1', [req.params.id]);
    var contacts = await pool.query('SELECT * FROM contact_log WHERE record_id = $1 ORDER BY created_at DESC', [req.params.id]);
    var docs = await pool.query('SELECT * FROM documents WHERE record_id = $1 ORDER BY created_at DESC', [req.params.id]);
    var notes = await pool.query('SELECT * FROM raw_notes WHERE record_id = $1 ORDER BY created_at DESC', [req.params.id]);
    if (!record.rows[0]) return res.status(404).json({ success: false, error: 'Not found' });
    res.json({ success: true, record: record.rows[0], contacts: contacts.rows, documents: docs.rows, notes: notes.rows });
  } catch (err) { res.status(500).json({ success: false, error: err.message }); }
});

